  1	import * as React from 'react';
  2	import { getReplicationHealth } from '@odf/mco/utils';
  3	import { ACM_DEFAULT_DOC_VERSION } from '@odf/shared/constants';
  4	import { utcDateTimeFormatter } from '@odf/shared/details-page/datetime';
  5	import { useDocVersion, DOC_VERSION as mcoDocVersion } from '@odf/shared/hooks';
  6	import { ResourceIcon } from '@odf/shared/resource-link/resource-link';
  7	import {
  8	  RedExclamationCircleIcon,
  9	  GreenCheckCircleIcon,
 10	} from '@odf/shared/status/icons';
 11	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 12	import {
 13	  StatusIconAndText,
 14	  K8sModel,
 15	  K8sResourceCondition,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import {
 18	  Flex,
 19	  FlexItem,
 20	  HelperText,
 21	  HelperTextItem,
 22	  Alert,
 23	  AlertProps,
 24	} from '@patternfly/react-core';
 25	import { UnknownIcon } from '@patternfly/react-icons';
 26	import {
 27	  DRActionType,
 28	  ReplicationType,
 29	  ACM_OPERATOR_SPEC_NAME,
 30	  VolumeReplicationHealth,
 31	} from '../../../constants';
 32	import {
 33	  ErrorMessageType,
 34	  evaluateErrorMessage,
 35	  ErrorMessages,
 36	  MessageKind,
 37	} from './helper/error-messages';
 38	import './failover-relocate-modal-body.scss';
 39	
 40	const failoverPreCheck = (placementControl: PlacementControlProps) => {
 41	  // Failover pre-check
 42	  if (placementControl?.isTargetClusterAvailable) {
 43	    if (placementControl?.replicationType === ReplicationType.SYNC) {
 44	      if (!placementControl?.isPrimaryClusterFenced) {
 45	        // Primary cluster is unfenced
 46	        return ErrorMessageType.PRIMARY_CLUSTER_IS_NOT_FENCED;
 47	      }
 48	      if (placementControl?.isTargetClusterFenced) {
 49	        // Target cluster is fenced
 50	        return ErrorMessageType.TARGET_CLUSTER_IS_FENCED;
 51	      }
 52	    }
 53	  } else {
 54	    // Target cluster is down
 55	    return ErrorMessageType.TARGET_CLUSTER_IS_NOT_AVAILABLE;
 56	  }
 57	};
 58	
 59	const relocatePreCheck = (placementControl: PlacementControlProps) => {
 60	  // Relocate pre-check
 61	  if (
 62	    placementControl?.isTargetClusterAvailable &&
 63	    placementControl?.isPrimaryClusterAvailable
 64	  ) {
 65	    if (placementControl?.replicationType === ReplicationType.SYNC) {
 66	      if (
 67	        placementControl?.isPrimaryClusterFenced ||
 68	        placementControl?.isTargetClusterFenced
 69	      ) {
 70	        // Either Primary cluster or target cluster is fenced
 71	        return ErrorMessageType.SOME_CLUSTERS_ARE_FENCED;
 72	      }
 73	    }
 74	  } else {
 75	    // Either target cluster or Primary cluster is down
 76	    return ErrorMessageType.MANAGED_CLUSTERS_ARE_DOWN;
 77	  }
 78	};
 79	
 80	const validatePlacement = (
 81	  placementControl: PlacementControlProps,
 82	  action: DRActionType
 83	): ErrorMessageType => {
 84	  const isFailoverAction = action === DRActionType.FAILOVER;
 85	
 86	  // Check if DR is invalid
 87	  if (placementControl?.invalidDRPolicy) {
 88	    return ErrorMessageType.DR_IS_INVALID;
 89	  }
 90	  // Check if DR is disabled
 91	  if (!placementControl?.drPlacementControlName) {
 92	    return isFailoverAction
 93	      ? ErrorMessageType.DR_IS_NOT_ENABLED_FAILOVER
 94	      : ErrorMessageType.DR_IS_NOT_ENABLED_RELOCATE;
 95	  }
 96	
 97	  // Check if DR action is ready
 98	  // Either Peer is not ready for DR failover
 99	  // Or, Peer is not ready/available for DR relocate
100	  if (!placementControl?.isDRActionReady) {
101	    return isFailoverAction
102	      ? ErrorMessageType.FAILOVER_READINESS_CHECK_FAILED
103	      : ErrorMessageType.RELOCATE_READINESS_CHECK_FAILED;
104	  }
105	
106	  // Perform failover or relocate pre-check
107	  const preCheckError = isFailoverAction
108	    ? failoverPreCheck(placementControl)
109	    : relocatePreCheck(placementControl);
110	
111	  if (preCheckError) {
112	    return preCheckError;
113	  }
114	
115	  // Check volume replication health
116	  if (
117	    [
118	      VolumeReplicationHealth.CRITICAL,
119	      VolumeReplicationHealth.WARNING,
120	    ].includes(
121	      getReplicationHealth(
122	        placementControl?.snapshotTakenTime,
123	        placementControl?.schedulingInterval,
124	        placementControl?.replicationType
125	      )
126	    )
127	  ) {
128	    return isFailoverAction
129	      ? ErrorMessageType.VOLUME_SYNC_DELAY_FAILOVER
130	      : ErrorMessageType.VOLUME_SYNC_DELAY_RELOCATE;
131	  }
132	
133	  // Check if sibling applications are found
134	  if (placementControl?.areSiblingApplicationsFound) {
135	    return isFailoverAction
136	      ? ErrorMessageType.SIBLING_APPLICATIONS_FOUND_FAILOVER
137	      : ErrorMessageType.SIBLING_APPLICATIONS_FOUND_RELOCATE;
138	  }
139	
140	  return null;
141	};
142	
143	const MessageStatus = ({ message }: { message: MessageKind }) => (
144	  <Flex>
145	    <FlexItem fullWidth={{ default: 'fullWidth' }}>
146	      <Alert
147	        data-test="dr-message-status"
148	        className="mco-dr-action-body__alert"
149	        title={message?.title}
150	        variant={message?.variant}
151	        isInline
152	      >
153	        {message?.message}
154	      </Alert>
155	    </FlexItem>
156	  </Flex>
157	);
158	
159	const TargetClusterStatus = ({
160	  targetClusterName,
161	  isClusterAvailable,
162	}: {
163	  targetClusterName: string;
164	  isClusterAvailable: boolean;
165	}) => {
166	  return (
167	    <StatusIconAndText
168	      title={targetClusterName}
169	      icon={
170	        isClusterAvailable ? (
171	          <GreenCheckCircleIcon />
172	        ) : (
173	          <RedExclamationCircleIcon />
174	        )
175	      }
176	    />
177	  );
178	};
179	
180	export const DateTimeFormat: React.FC<{
181	  dateTime: string;
182	  className?: string;
183	}> = ({ dateTime, className }) => {
184	  const { t } = useCustomTranslation();
185	  return !!dateTime ? (
186	    <>{utcDateTimeFormatter.format(new Date(dateTime))}</>
187	  ) : (
188	    <StatusIconAndText
189	      title={t('Unknown')}
190	      icon={<UnknownIcon />}
191	      className={className}
192	    />
193	  );
194	};
195	
196	const DRActionReadiness = ({ canInitiate }: { canInitiate: boolean }) => {
197	  const { t } = useCustomTranslation();
198	  return canInitiate ? (
199	    <StatusIconAndText title={t('Ready')} icon={<GreenCheckCircleIcon />} />
200	  ) : (
201	    <StatusIconAndText
202	      title={t('Not ready')}
203	      icon={<RedExclamationCircleIcon />}
204	    />
205	  );
206	};
207	
208	export const FailoverRelocateModalBody: React.FC<
209	  FailoverRelocateModalBodyProps
210	> = (props) => {
211	  const { t } = useCustomTranslation();
212	  const {
213	    action,
214	    applicationName,
215	    canInitiate,
216	    setCanInitiate,
217	    setPlacement,
218	    placementControls,
219	    loadError,
220	    loaded,
221	    applicationModel,
222	    message,
223	  } = props;
224	  const [errorMessage, setErrorMessage] = React.useState<ErrorMessageType>();
225	  const placement = placementControls?.[0];
226	
227	  const acmDocVersion = useDocVersion({
228	    defaultDocVersion: ACM_DEFAULT_DOC_VERSION,
229	    specName: ACM_OPERATOR_SPEC_NAME,
230	  });
231	
232	  React.useEffect(() => {
233	    if (loaded && !loadError) {
234	      const placementErrorMessage = validatePlacement(placement, action);
235	      setErrorMessage(placementErrorMessage);
236	      setPlacement(placement);
237	      setCanInitiate(evaluateErrorMessage(placementErrorMessage) < 0);
238	    }
239	  }, [
240	    placement,
241	    action,
242	    loadError,
243	    loaded,
244	    setCanInitiate,
245	    setPlacement,
246	    setErrorMessage,
247	  ]);
248	
249	  return (
250	    <>
251	      {!!message && <Alert {...message} className="pf-v6-u-mb-md" />}
252	      <Flex
253	        direction={{ default: 'column' }}
254	        spaceItems={{ default: 'spaceItemsMd' }}
255	      >
256	        <Flex>
257	          <FlexItem>
258	            <strong> {t('Application:')} </strong>
259	          </FlexItem>
260	          <FlexItem data-test="app-name">
261	            <ResourceIcon resourceModel={applicationModel} />
262	            {applicationName || (
263	              <StatusIconAndText title={t('Unknown')} icon={<UnknownIcon />} />
264	            )}
265	          </FlexItem>
266	        </Flex>
267	        <Flex justifyContent={{ default: 'justifyContentFlexStart' }}>
268	          <FlexItem>
269	            <strong> {t('Target cluster:')} </strong>
270	          </FlexItem>
271	          <FlexItem className="mco-dr-action-body__target-cluster--width">
272	            {!!placement?.targetClusterName ? (
273	              <TargetClusterStatus
274	                targetClusterName={placement?.targetClusterName}
275	                isClusterAvailable={placement?.isTargetClusterAvailable}
276	              />
277	            ) : (
278	              <StatusIconAndText title={t('Unknown')} icon={<UnknownIcon />} />
279	            )}
280	          </FlexItem>
281	          <FlexItem>
282	            <HelperText>
283	              <HelperTextItem variant="indeterminate">
284	                {t('Last available: ')}
285	                <DateTimeFormat
286	                  dateTime={placement?.targetClusterAvailableTime}
287	                  className="pf-v6-u-display-inline-block pf-v6-u-ml-sm"
288	                />
289	              </HelperTextItem>
290	            </HelperText>
291	          </FlexItem>
292	        </Flex>
293	        <Flex>
294	          <FlexItem>
295	            <strong>
296	              {t('{{actionType}} readiness:', {
297	                actionType: action,
298	              })}
299	            </strong>
300	          </FlexItem>
301	          <FlexItem>
302	            <DRActionReadiness canInitiate={canInitiate} />
303	          </FlexItem>
304	        </Flex>
305	        {placement?.replicationType === ReplicationType.ASYNC && (
306	          <Flex>
307	            <FlexItem>
308	              <strong>{t('Volume last synced on:')}</strong>
309	            </FlexItem>
310	            <FlexItem>
311	              <DateTimeFormat dateTime={placement?.snapshotTakenTime} />
312	            </FlexItem>
313	          </Flex>
314	        )}
315	
316	        {
317	          // ToDo: Enable this once DRPC has kube object last sync time.
318	          /*applicationModel.kind === DRPlacementControlModel.kind && (
319	            <Flex>
320	              <FlexItem>
321	                <strong>{t('Kubernetes object last synced on:')}</strong>
322	              </FlexItem>
323	              <FlexItem>
324	                <DateTimeFormat dateTime={placement?.kubeObjectLastSyncTime} />
325	              </FlexItem>
326	            </Flex>
327	          )*/
328	        }
329	        {evaluateErrorMessage(errorMessage, true) > -1 && (
330	          <MessageStatus
331	            message={
332	              ErrorMessages(
333	                t,
334	                mcoDocVersion,
335	                acmDocVersion,
336	                placement?.invalidDRPolicy
337	              )[errorMessage]
338	            }
339	          />
340	        )}
341	      </Flex>
342	    </>
343	  );
344	};
345	
346	export type PlacementControlProps = Partial<{
347	  placementName: string;
348	  drPlacementControlName: string;
349	  targetClusterName: string;
350	  targetClusterAvailableTime: string;
351	  primaryClusterName: string;
352	  snapshotTakenTime: string;
353	  isTargetClusterAvailable: boolean;
354	  isPrimaryClusterAvailable: boolean;
355	  isDRActionReady: boolean;
356	  replicationType: ReplicationType;
357	  isTargetClusterFenced: boolean;
358	  isPrimaryClusterFenced: boolean;
359	  areSiblingApplicationsFound: boolean;
360	  kubeObjectLastSyncTime: string;
361	  schedulingInterval: string;
362	  invalidDRPolicy: K8sResourceCondition;
363	}>;
364	
365	export type ApplicationProps = {
366	  applicationName: string;
367	  applicationNamespace: string;
368	  applicationModel: K8sModel;
369	  placementControls: PlacementControlProps[];
370	  action: DRActionType;
371	  message?: AlertProps;
372	  loadError: any;
373	  loaded: boolean;
374	};
375	
376	export type FailoverRelocateModalBodyProps = ApplicationProps & {
377	  canInitiate: boolean;
378	  setCanInitiate: React.Dispatch<React.SetStateAction<boolean>>;
379	  setPlacement: React.Dispatch<React.SetStateAction<PlacementControlProps>>;
380	};

